var maximumWealth = function (accounts) {
    let maxWealth = 0
    for (let account of accounts) {
        let wealth = account.reduce((acc, curr) => acc + curr, 0)
        maxWealth = Math.max(maxWealth, wealth)
    }
    return maxWealth;
};

var twoSum = function (nums, target) {
    const history = new Map()
    for (let i = 0; i < nums.length; i++) {
        const diff = target - nums[i]
        if (history.has(diff)) {
            return [history.get(diff), i]
        } else {
            history.set(nums[i], i)
        }
    }
};

var countNegatives = function (grid) {
    let m = grid.length;
    let n = grid[0].length;
    let row = m - 1 // last row
    let col = 0
    let count = 0

    while (row >= 0 && col < n) {
        if (grid[row][col] < 0) { // first -ve num
            count += (n - col)
            row--;
        } else {
            col++;
        }
    }
    return count;
};

var nextPermutation = function (nums) {
    let n = nums.length;
    // STEP 1: find breaking point
    let pivot = -1;
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            pivot = i;
            break;
        }
    }
    // if no pivot => reverse whole array
    if (pivot === -1) {
        nums.reverse();
        return;
    }
    // STEP 2: find next greater element
    for (let i = n - 1; i > pivot; i--) {
        if (nums[i] > nums[pivot]) {
            [nums[i], nums[pivot]] = [nums[pivot], nums[i]];
            break;
        }
    }
    // STEP 3: reverse suffix
    let left = pivot + 1;
    let right = n - 1;
    while (left < right) {
        [nums[left], nums[right]] = [nums[right], nums[left]];
        left++;
        right--;
    }
}

var findMedianSortedArrays = function (nums1, nums2) {
    const result = [...nums1, ...nums2].sort((a, b) => a - b)
    const n = result.length
    let median = 0
    if (n % 2 === 0) {
        median = (result[Math.floor(n / 2)] + result[Math.floor(n / 2) - 1]) / 2
    } else {
        median = result[Math.floor(n / 2)]
    }
    return median
};

var findGCD = function (nums) {
    const arr = nums.sort((a, b) => a - b)
    let maxCommon = 1
    for (let i = 0; i <= arr[0]; i++) {
        if (arr[arr.length - 1] % i === 0 && arr[0] % i === 0) {
            maxCommon = Math.max(maxCommon, i)
        }
    }
    return maxCommon
};

var selfDividingNumbers = function (left, right) {
    if (left > right) return []
    const result = []
    for (let i = left; i <= right; i++) {
        let temp = i.toString().split('')
        let count = 0
        for (let j = 0; j < temp.length; j++) {
            if (i % Number(temp[j]) === 0) {
                count++
            }
            if (count === temp.length) {
                result.push(i)
            }
        }
    }
    return result
};

var reversePairs = function (nums) {
    let count = 0;
    const mergeSort = (left, right) => {
        // base case
        if (left >= right) return;
        let mid = Math.floor((left + right) / 2);
        mergeSort(left, mid);
        mergeSort(mid + 1, right);
        // count reverse pairs
        let j = mid + 1;
        for (let i = left; i <= mid; i++) {
            while (j <= right && nums[i] > 2 * nums[j]) {
                j++;
            }
            count += j - (mid + 1);
        }
        // merge step
        let temp = [];
        let i = left;
        j = mid + 1;
        while (i <= mid && j <= right) {
            if (nums[i] <= nums[j]) {
                temp.push(nums[i]);
                i++;
            } else {
                temp.push(nums[j]);
                j++;
            }
        }
        while (i <= mid) {
            temp.push(nums[i]);
            i++;
        }
        while (j <= right) {
            temp.push(nums[j]);
            j++;
        }
        for (let k = left; k <= right; k++) {
            nums[k] = temp[k - left];
        }
    };

    mergeSort(0, nums.length - 1);
    return count;
};

var numSpecial = function (mat) {
    let m = mat.length
    let n = mat[0].length
    let rowCount = new Array(m).fill(0)
    let colCount = new Array(n).fill(0)
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (mat[i][j] === 1) {
                rowCount[i]++
                colCount[j]++
            }
        }
    }
    let count = 0
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (mat[i][j] === 1 && rowCount[i] === 1 && colCount[j] === 1) {
                count++;
            }
        }
    }
    return count
};

var transpose = function (matrix) {
    let m = matrix.length
    let n = matrix[0].length
    let result = new Array(n).fill(0).map(() => new Array(m))

    for (let i = 0; i < n; i++) {
        for (let j = 0; j < m; j++) {
            result[i][j] = matrix[j][i]
        }
    }

    return result
};

var updateMatrix = function (mat) {
    let m = mat.length;
    let n = mat[0].length;
    let queue = [];

    // Step 1: Put all 0s into queue
    // and mark 1s as Infinity
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (mat[i][j] === 0) {
                queue.push([i, j]);
            } else {
                mat[i][j] = Infinity;
            }
        }
    }

    // 4 directions
    let dirs = [[1, 0], [-1, 0],[0, 1],[0, -1]];

    // Step 2: BFS
    while (queue.length > 0) {
        let [r, c] = queue.shift();

        for (let [dr, dc] of dirs) {
            let nr = r + dr;
            let nc = c + dc;

            // boundary check
            if (nr >= 0 && nr < m &&
                nc >= 0 && nc < n
            ) {
                // If shorter distance found
                if (mat[nr][nc] > mat[r][c] + 1) {
                    mat[nr][nc] = mat[r][c] + 1;
                    queue.push([nr, nc]);
                }
            }
        }
    }

    return mat;
};

var spiralOrder = function (matrix) {
    const res = [];
    let top = 0;
    let bottom = matrix.length - 1;
    let left = 0;
    let right = matrix[0].length - 1;

    while (top <= bottom && left <= right) {
        // LEFT → RIGHT
        for (let j = left; j <= right; j++) {
            res.push(matrix[top][j]);
        }
        top++;

        // TOP → BOTTOM
        for (let i = top; i <= bottom; i++) {
            res.push(matrix[i][right]);
        }
        right--;

        // RIGHT → LEFT
        if (top <= bottom) {
            for (let j = right; j >= left; j--) {
                res.push(matrix[bottom][j]);
            }
            bottom--;
        }

        // BOTTOM → TOP
        if (left <= right) {
            for (let i = bottom; i >= top; i--) {
                res.push(matrix[i][left]);
            }
            left++;
        }
    }

    return res;
};

var generate = function (numRows) {
    const res = []
    for (let i = 0; i < numRows; i++) {
        let row = new Array(i + 1).fill(1)

        for (let j = 1; j < i; j++) {
            row[j] = res[i - 1][j - 1] + res[i - 1][j]
        }
        res.push(row)
    }
    return res
};

var minSubArrayLen = function (target, arr) {
    let minSub = Infinity;
    let windowSum = 0;
    let start = 0;
    for (let end = 0; end < arr.length; end++) {
        windowSum += arr[end];
        while (windowSum >= target) {
            minSub = Math.min(minSub, end - start + 1)
            windowSum -= arr[start];
            start++;
        }
    }
    return minSub === Infinity ? 0 : minSub;
};

var runningSum = function (nums) {
    const n = nums.length
    const prefix = new Array(n + 1).fill(0)
    for (let i = 1; i <= n; i++) {
        prefix[i] = prefix[i - 1] + nums[i - 1]
    }
    prefix.shift()
    return prefix
};

var NumMatrix = function (matrix) {
    let rows = matrix.length;
    let cols = matrix[0].length;

    // Extra row and column
    this.prefix = Array(rows + 1)
        .fill(0)
        .map(() => Array(cols + 1).fill(0));

    // Build prefix sum
    for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {

            this.prefix[r + 1][c + 1] =
                matrix[r][c]
                + this.prefix[r][c + 1]
                + this.prefix[r + 1][c]
                - this.prefix[r][c];
        }
    }
};


NumMatrix.prototype.sumRegion = function (row1, col1, row2, col2) {
    return (
        this.prefix[row2 + 1][col2 + 1]
        - this.prefix[row1][col2 + 1]
        - this.prefix[row2 + 1][col1]
        + this.prefix[row1][col1]
    );
};

var maxSubArray = function (nums) {
    let currentSum = nums[0]
    let maxSum = nums[0]
    for (let i = 1; i < nums.length; i++) {
        currentSum = Math.max(nums[i], nums[i] + currentSum)
        maxSum = Math.max(currentSum, maxSum)
    }
    return maxSum;
};

var maxSubarraySumCircular = function (nums) {
    let total = 0
    let curMax = 0
    let maxSum = nums[0]
    let curMin = 0
    let minSum = nums[0]

    for (let num of nums) {
        // Kadane for maximum
        curMax = Math.max(curMax + num, num)
        maxSum = Math.max(maxSum, curMax)

        // Kadane for minimum
        curMin = Math.min(curMin + num, num)
        minSum = Math.min(minSum, curMin)

        total += num
    }
    // all negative case
    if (maxSum < 0) return maxSum

    return Math.max(maxSum, total - minSum)
};

var maxTurbulenceSize = function (arr) {
    const n = arr.length
    if (n === 1) return 1
    let maxLen = 1
    let up = 1
    let down = 1
    for (let i = 1; i < n; i++) {
        if (arr[i] > arr[i - 1]) {
            up = down + 1
            down = 1
        } else if (arr[i] < arr[i - 1]) {
            down = up + 1
            up = 1
        } else {
            up = 1
            down = 1
        }
        maxLen = Math.max(maxLen, up, down)
    }
    return maxLen
};

var containsNearbyDuplicate = function (nums, k) {
    let window = new Set();
    let left = 0;

    for (let right = 0; right < nums.length; right++) {
        // duplicate inside window
        if (window.has(nums[right])) {
            return true;
        }
        window.add(nums[right]);
        // maintain window size <= k
        if (right - left >= k) {
            window.delete(nums[left]);
            left++;
        }
    }

    return false;
};

var numOfSubarrays = function (arr, k, threshold) {
    let windowSum = 0;
    let count = 0
    let start = 0;
    for (let end = 0; end < arr.length; end++) {
        windowSum += arr[end];
        if (end - start + 1 === k) {
            if (Math.floor(windowSum / k) >= threshold) count++;
            windowSum -= arr[start];
            start++;
        }
    }
    return count;
};

