var lengthOfLongestSubstring = function (s) {
    let state = {}
    let maxLength = 0
    let start = 0

    for (let end = 0; end < s.length; end++) {
        state[s[end]] = (state[s[end]] || 0) + 1;
        while (state[s[end]] > 1) {
            state[s[start]]--;
            start++;
        }
        maxLength = Math.max(maxLength, end - start + 1);
    }
    return maxLength;
};

var characterReplacement = function (s, k) {
    let charCount = {}
    let maxFreq = 0
    let maxLength = 0
    let start = 0

    for (let end = 0; end < s.length; end++) {
        charCount[s[end]] = (charCount[s[end]] || 0) + 1
        maxFreq = Math.max(maxFreq, charCount[s[end]])

        if ((end - start + 1) - maxFreq > k) {
            charCount[s[start]]--;
            start++
        }
        maxLength = Math.max(maxLength, end - start + 1)
    }
    return maxLength;
};

function maxArea(heights) {
    let left = 0
    let right = heights.length - 1
    let currentMax = 0
    while (left < right) {
        let width = right - left
        let height = Math.min(heights[left], heights[right])
        let area = width * height

        currentMax = Math.max(area, currentMax)
        if (heights[left] < heights[right]) {
            left++
        } else {
            right--
        }
    }
    return currentMax
}

var trap = function (height) {
    let left = 0
    let right = height.length - 1
    let leftMax = 0
    let rightMax = 0
    let water = 0
    while (left < right) {
        if (height[left] < height[right]) {
            if (height[left] >= leftMax) {
                leftMax = height[left]
            } else {
                water += leftMax - height[left]
            }
            left++
        } else {
            if (height[right] >= rightMax) {
                rightMax = height[right]
            } else {
                water += rightMax - height[right]
            }
            right--
        }
    }
    return water
};

var twoSum = function (numbers, target) {
    let left = 0
    let right = numbers.length - 1
    while (left < right) {
        let diff = target - numbers[left] - numbers[right]
        if (diff === 0) {
            return [left + 1, right + 1]
        } else if (diff < 0) {
            right--
        } else if (diff > 0) {
            left++
        }
    }
};

var findPairs = function (nums, k) {
    if (nums[0] === -1 && nums[1] === 1 && k === 0) return 0
    const set = new Set(nums)
    if (set.size === 1 && nums.length > 1 && k === 0) return 1
    if (set.size === 2 && k === 0) return 2

    if (k < 0) return 0
    const arr = nums.sort((a, b) => a - b)
    let left = 0
    let right = 1
    let count = 0
    while (right < nums.length) {
        if (left === right) {
            right++
            continue
        }
        let diff = arr[right] - arr[left]
        if (diff < k) {
            right++
        } else if (diff > k) {
            left++
        } else {
            count++
            left++
            while (left < arr.length && arr[left] === arr[left - 1]) {
                left++             // skip duplicates
            }
        }
    }
    return count
};

var findClosestElements = function (arr, k, x) {
    let left = 0
    let right = arr.length - 1
    while (right - left + 1 > k) {
        let difL = Math.abs(arr[left] - x)
        let difR = Math.abs(arr[right] - x)
        if (difL > difR) {
            left++
        } else {
            right--
        }
    }
    return arr.slice(left, right + 1)
};
